from pathlib import Path

bot_path = Path('/var/www/bazaar/eth_scalper/bot/main.py')
text = bot_path.read_text()
repls = {
    'REENTRY_SCORE_THRESHOLD = 0.42': 'REENTRY_SCORE_THRESHOLD = 0.50',
    'REENTRY_SCORE_ARM_THRESHOLD = 0.34': 'REENTRY_SCORE_ARM_THRESHOLD = 0.42',
    'REENTRY_RECOVER_ABOVE_SELL_PCT = 0.30': 'REENTRY_RECOVER_ABOVE_SELL_PCT = 0.22',
    'MISSED_REENTRY_RECOVERY_PCT = 0.55': 'MISSED_REENTRY_RECOVERY_PCT = 0.40',
    'REENTRY_PARITY_BAND_PCT = 0.06': 'REENTRY_PARITY_BAND_PCT = 0.04',
}
orig = text
for a,b in repls.items():
    text = text.replace(a,b)
if text != orig:
    Path('/var/www/bazaar/eth_scalper/bot/main.py.tune2bak').write_text(orig)
    bot_path.write_text(text)

